import './styles.css';

document.addEventListener('DOMContentLoaded', () => {
  // ==========================================================================
  // 1. Hero Image Slideshow
  // ==========================================================================
  const heroImages = document.querySelectorAll('.hero__img');
  const heroDots = document.querySelectorAll('.hero__dot');
  let currentHeroIndex = 0;
  let heroIntervalId = null;

  function showHeroImage(index) {
    heroImages.forEach((img, i) => {
      if (i === index) {
        img.classList.add('active');
        heroDots[i].classList.add('active');
      } else {
        img.classList.remove('active');
        heroDots[i].classList.remove('active');
      }
    });
    currentHeroIndex = index;
  }

  function startHeroSlideshow() {
    heroIntervalId = setInterval(() => {
      let nextIndex = (currentHeroIndex + 1) % heroImages.length;
      showHeroImage(nextIndex);
    }, 4500);
  }

  function resetHeroSlideshow() {
    if (heroIntervalId) {
      clearInterval(heroIntervalId);
    }
    startHeroSlideshow();
  }

  heroDots.forEach((dot, index) => {
    dot.addEventListener('click', () => {
      showHeroImage(index);
      resetHeroSlideshow();
    });
  });

  // Start the slideshow
  startHeroSlideshow();


  // ==========================================================================
  // 2. Testimonials Slider (with CSS Scroll Snap + JS Controls Sync)
  // ==========================================================================
  const slider = document.getElementById('testimonials-slider');
  const btnPrev = document.getElementById('testimonials-prev');
  const btnNext = document.getElementById('testimonials-next');
  const paginationContainer = document.getElementById('testimonials-pagination');
  
  if (slider && btnPrev && btnNext) {
    const cards = slider.querySelectorAll('.testimonials__card');
    const totalCards = cards.length;
    
    // Create pagination dots
    for (let i = 0; i < totalCards; i++) {
      const dot = document.createElement('button');
      dot.className = `testimonials__pagination-dot ${i === 0 ? 'active' : ''}`;
      dot.setAttribute('aria-label', `Ir para depoimento ${i + 1}`);
      dot.addEventListener('click', () => {
        const cardWidth = cards[0].offsetWidth + 20; // card width + gap
        slider.scrollTo({
          left: i * cardWidth,
          behavior: 'smooth'
        });
      });
      paginationContainer.appendChild(dot);
    }

    const dots = paginationContainer.querySelectorAll('.testimonials__pagination-dot');

    // Sync dots on scroll
    let scrollTimeout;
    slider.addEventListener('scroll', () => {
      clearTimeout(scrollTimeout);
      scrollTimeout = setTimeout(() => {
        const cardWidth = cards[0].offsetWidth + 20;
        const scrollPosition = slider.scrollLeft;
        const activeIndex = Math.round(scrollPosition / cardWidth);
        
        dots.forEach((dot, idx) => {
          if (idx === activeIndex) {
            dot.classList.add('active');
          } else {
            dot.classList.remove('active');
          }
        });
      }, 50);
    });

    // Prev / Next button actions
    btnPrev.addEventListener('click', () => {
      const cardWidth = cards[0].offsetWidth + 20;
      slider.scrollBy({
        left: -cardWidth,
        behavior: 'smooth'
      });
    });

    btnNext.addEventListener('click', () => {
      const cardWidth = cards[0].offsetWidth + 20;
      slider.scrollBy({
        left: cardWidth,
        behavior: 'smooth'
      });
    });
  }


  // ==========================================================================
  // 3. FAQ Accordion (with Smooth Heights)
  // ==========================================================================
  const faqQuestions = document.querySelectorAll('.faq__question');

  faqQuestions.forEach(btn => {
    btn.addEventListener('click', () => {
      const item = btn.parentElement;
      const answer = item.querySelector('.faq__answer');
      const isExpanded = btn.getAttribute('aria-expanded') === 'true';

      // Close all other FAQ items for clean accordion behavior
      document.querySelectorAll('.faq__item').forEach(otherItem => {
        if (otherItem !== item) {
          otherItem.classList.remove('active');
          const otherBtn = otherItem.querySelector('.faq__question');
          otherBtn.setAttribute('aria-expanded', 'false');
          const otherAnswer = otherItem.querySelector('.faq__answer');
          otherAnswer.style.maxHeight = '0px';
          otherAnswer.style.opacity = '0';
          setTimeout(() => {
            otherAnswer.setAttribute('hidden', '');
          }, 300);
        }
      });

      if (isExpanded) {
        // Close current
        btn.setAttribute('aria-expanded', 'false');
        answer.style.maxHeight = '0px';
        answer.style.opacity = '0';
        item.classList.remove('active');
        setTimeout(() => {
          answer.setAttribute('hidden', '');
        }, 300);
      } else {
        // Open current
        answer.removeAttribute('hidden');
        // Let browser calculate scrollHeight on next frame
        requestAnimationFrame(() => {
          btn.setAttribute('aria-expanded', 'true');
          answer.style.maxHeight = `${answer.scrollHeight}px`;
          answer.style.opacity = '1';
          item.classList.add('active');
        });
      }
    });
  });


  // ==========================================================================
  // 4. Floating WhatsApp Button Smart Visibility & Analytics Click Tracking
  // ==========================================================================
  const whatsappFloatingBtn = document.getElementById('whatsapp-floating-button');
  
  if (whatsappFloatingBtn) {
    // Hide initially via styling, but handle dynamically here
    whatsappFloatingBtn.style.opacity = '0';
    whatsappFloatingBtn.style.pointerEvents = 'none';
    whatsappFloatingBtn.style.transform = 'scale(0.8) translateY(20px)';
    whatsappFloatingBtn.style.transition = 'opacity 0.4s ease, transform 0.4s ease, background-color 0.3s ease, box-shadow 0.3s ease';

    window.addEventListener('scroll', () => {
      if (window.scrollY > 400) {
        whatsappFloatingBtn.style.opacity = '1';
        whatsappFloatingBtn.style.pointerEvents = 'all';
        whatsappFloatingBtn.style.transform = 'scale(1) translateY(0)';
      } else {
        whatsappFloatingBtn.style.opacity = '0';
        whatsappFloatingBtn.style.pointerEvents = 'none';
        whatsappFloatingBtn.style.transform = 'scale(0.8) translateY(20px)';
      }
    }, { passive: true });
  }

  // Tracking Click Events (Simulado / Pronto para GTM / Pixel)
  const trackCtaClick = (buttonId, location) => {
    console.log(`[Ostomania Analytics] CTA Clicado: ${buttonId} na seção ${location}`);
    // Aqui podem ser adicionados fbq('track', 'Contact') ou gtag('event', 'click_whatsapp')
  };

  document.querySelectorAll('a[href*="wa.me"]').forEach(link => {
    link.addEventListener('click', (e) => {
      const id = link.getAttribute('id') || 'whatsapp-link';
      const section = link.closest('section')?.getAttribute('id') || 'floating';
      trackCtaClick(id, section);
    });
  });
});
